-- Import historical expenses from CSV (Feb 15 - May 6, 2026)
-- Total: 261 expenses, Total amount: ৳1,619,765.60

DO $$
DECLARE
  v_store_id uuid;
BEGIN
  SELECT id INTO v_store_id FROM stores LIMIT 1;
  IF v_store_id IS NULL THEN
    RAISE EXCEPTION 'No store found';
  END IF;


  RAISE NOTICE 'Imported 261 expenses successfully';
END $$;
